import { GoogleGenAI, Type } from "@google/genai";

const getAIClient = () => {
    if (!process.env.API_KEY) throw new Error("Chave de API do Gemini não configurada.");
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

// Trava Global de Processamento para evitar chamadas duplicadas/concorrentes
let isAIBusy = false;

const safeJsonParse = (input: any, fallback: any = []) => {
    if (!input) return fallback;
    let sanitized = String(input).trim();
    sanitized = sanitized.replace(/^```json\s*/g, '').replace(/\s*```$/g, '');

    try {
        const parsed = JSON.parse(sanitized);
        if (parsed.rows) return parsed.rows;
        if (parsed.transactions) return parsed.transactions;
        return Array.isArray(parsed) ? parsed : fallback;
    } catch (e) {
        console.error("[GeminiService] Erro ao parsear JSON da IA:", e, sanitized);
        return fallback;
    }
};

/**
 * 🛠️ DUMP ESTRUTURAL (MODO LABORATÓRIO)
 * Fatiado para enviar apenas os primeiros 4000 caracteres para identificação de padrão.
 */
export const getRawStructuralDump = async (base64Data: string): Promise<any[]> => {
    if (isAIBusy) return [];
    isAIBusy = true;

    try {
        const ai = getAIClient();
        const instruction = `TRANSCRITOR LITERAL. Liste fragmentos de texto do documento num array JSON "rawLines". Sem colunas, sem interpretação.`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview', // Flash para tarefas simples de dump
            contents: {
                parts: [
                    { inlineData: { data: base64Data, mimeType: 'application/pdf' } },
                    { text: instruction }
                ]
            },
            config: {
                temperature: 0,
                maxOutputTokens: 1000,
                thinkingConfig: { thinkingBudget: 0 },
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        rawLines: { type: Type.ARRAY, items: { type: Type.STRING } }
                    },
                    required: ["rawLines"]
                }
            }
        });

        const result = JSON.parse(response.text || '{"rawLines": []}');
        return result.rawLines || [];
    } finally {
        isAIBusy = false;
    }
};

/**
 * INFRE MAPPING FROM SAMPLE
 * Limita a amostra de texto para economizar tokens.
 */
export const inferMappingFromSample = async (sampleText: string): Promise<any> => {
    if (isAIBusy) return null;
    isAIBusy = true;

    try {
        const ai = getAIClient();
        // Fatiamento: Envia apenas os primeiros 3000 caracteres para análise de estrutura
        const slicedText = sampleText.substring(0, 3000);
        const prompt = `Analise a estrutura física deste documento financeiro. TEXTO: ${slicedText}`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { 
                temperature: 0, 
                maxOutputTokens: 500,
                thinkingConfig: { thinkingBudget: 0 },
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        extractionMode: { type: Type.STRING },
                        dateColumnIndex: { type: Type.INTEGER },
                        descriptionColumnIndex: { type: Type.INTEGER },
                        amountColumnIndex: { type: Type.INTEGER },
                        skipRowsStart: { type: Type.INTEGER }
                    },
                    required: ["extractionMode", "dateColumnIndex", "descriptionColumnIndex", "amountColumnIndex", "skipRowsStart"]
                }
            }
        });
        return JSON.parse(response.text || "{}");
    } finally {
        isAIBusy = false;
    }
};

/**
 * 🎯 MOTOR DE EXTRAÇÃO RÍGIDO (Fidelidade Cega ao Contrato)
 * Implementa fatiamento de texto e limites estritos de saída.
 */
export const extractTransactionsWithModel = async (rawText: string, modelContext?: string, base64Data?: string): Promise<any> => {
    if (isAIBusy) return { rows: [] };
    isAIBusy = true;

    try {
        const ai = getAIClient();

        const instruction = `VOCÊ É UM ALGORITMO DE BUSCA DE PADRÕES. PROIBIDO SER INTELIGENTE.
           SUA ÚNICA TAREFA: Varrer o documento e encontrar TODAS as ocorrências que sigam EXATAMENTE este contrato:
           --- CONTRATO APRENDIDO ---
           ${modelContext}
           --------------------------
           FORMATO OBRIGATÓRIO: JSON com chave "rows" contendo array de {date, description, amount}.`;

        const contents: any = { parts: [] };

        if (base64Data) {
            // No modo visão (PDF/Img), o Gemini processa o contexto visual de uma vez, 
            // mas limitamos a saída para evitar tokens fantasmas.
            contents.parts.push({ inlineData: { data: base64Data, mimeType: 'application/pdf' } });
        } else if (rawText && rawText !== '[DOCUMENTO_VISUAL]' && rawText !== '[DOCUMENTO_PDF_VISUAL]') {
            // Fatiamento: Se o texto for muito grande, pegamos apenas um bloco processável (aprox 8000 chars por chamada)
            const slicedText = rawText.substring(0, 8000);
            contents.parts.push({ text: `TEXTO DO DOCUMENTO (BLOCO):\n${slicedText}` });
        }

        contents.parts.push({ text: instruction });

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview', // Flash é 10x mais barato e rápido para extração padrão
            contents: contents,
            config: {
                temperature: 0,
                maxOutputTokens: 2000, // Teto controlado para o array JSON
                thinkingConfig: { thinkingBudget: 0 },
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        rows: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    date: { type: Type.STRING },
                                    description: { type: Type.STRING },
                                    amount: { type: Type.NUMBER }
                                },
                                required: ["date", "description", "amount"]
                            }
                        }
                    },
                    required: ["rows"]
                }
            }
        });
        return safeJsonParse(response.text);
    } finally {
        isAIBusy = false;
    }
};

import { useState, useCallback } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { FileModel, Transaction } from '../types';

interface UseAIPatternTeacherProps {
    gridData: string[][];
    setGridData: (data: string[][]) => void;
    setActiveMapping: (mapping: any) => void;
    showToast: (msg: string, type: 'success' | 'error') => void;
    fullFileText?: string;
    rawBase64?: string; 
}

export const useAIPatternTeacher = ({
    gridData,
    setGridData,
    setActiveMapping,
    showToast,
    fullFileText,
    rawBase64
}: UseAIPatternTeacherProps) => {
    const [isInferringMapping, setIsInferringMapping] = useState(false);
    const [learnedPatternSource, setLearnedPatternSource] = useState<{ originalRaw: string[], corrected: any } | null>(null);

    const handleApplyCorrectionPattern = useCallback(async (extractionMode: 'COLUMNS' | 'BLOCK' = 'COLUMNS') => {
        if (!learnedPatternSource || isInferringMapping) return;

        setIsInferringMapping(true);
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

        try {
            const isBlockMode = extractionMode === 'BLOCK';

            const instruction = isBlockMode 
            ? `VOCÊ É UM ENGENHEIRO DE REPRODUÇÃO ESTRUTURAL. O Admin editou uma linha modelo para te ensinar como extrair dados.
            --- LINHA MODELO ---
            Bruto: "${learnedPatternSource.originalRaw.join(' | ')}"
            Esperado: Date:"${learnedPatternSource.corrected.date}" | Desc:"${learnedPatternSource.corrected.description}" | Amount:"${learnedPatternSource.corrected.amount}"
            Gere a "blockRecipe" JSON com a regra algorítmica e "confidence".`

            : `VOCÊ É UM EXTRATOR DE ÍNDICES DE COLUNA. Determine os índices de 0 a N correspondentes:
            BRUTO: "${learnedPatternSource.originalRaw.join(' ; ')}"
            GABARITO: Data: "${learnedPatternSource.corrected.date}", Nome: "${learnedPatternSource.corrected.description}", Valor: "${learnedPatternSource.corrected.amount}"`;

            const contents: any = { parts: [] };

            if (isBlockMode && rawBase64) {
                contents.parts.push({
                    inlineData: {
                        data: rawBase64,
                        mimeType: 'application/pdf'
                    }
                });
            } else if (fullFileText) {
                // FATIAMENTO: Envia apenas os primeiros 5000 caracteres como contexto para economizar tokens
                contents.parts.push({ text: `CONTEÚDO DO DOCUMENTO (AMOSTRA):\n${fullFileText.substring(0, 5000)}` });
            }

            contents.parts.push({ text: instruction });

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview', // Uso de modelo Flash para economia no treinamento
                contents: contents,
                config: { 
                    temperature: 0,
                    maxOutputTokens: 800,
                    thinkingConfig: { thinkingBudget: 0 },
                    responseMimeType: "application/json",
                    responseSchema: isBlockMode ? {
                        type: Type.OBJECT,
                        properties: {
                            blockRecipe: { type: Type.STRING },
                            confidence: { type: Type.NUMBER }
                        },
                        required: ["blockRecipe"]
                    } : {
                        type: Type.OBJECT,
                        properties: {
                            dateColumnIndex: { type: Type.INTEGER },
                            descriptionColumnIndex: { type: Type.INTEGER },
                            amountColumnIndex: { type: Type.INTEGER },
                            ignoredKeywords: { type: Type.ARRAY, items: { type: Type.STRING } }
                        },
                        required: ["dateColumnIndex", "descriptionColumnIndex", "amountColumnIndex", "ignoredKeywords"]
                    }
                }
            });

            const result = JSON.parse(response.text || "{}");

            setActiveMapping((prev: any) => {
                if (isBlockMode) {
                    return {
                        ...prev,
                        extractionMode: 'BLOCK',
                        blockContract: `CONTRATO RÍGIDO: [${learnedPatternSource.originalRaw.join(' | ')}] -> Date:${learnedPatternSource.corrected.date} | Desc:${learnedPatternSource.corrected.description} | Amount:${learnedPatternSource.corrected.amount}. REGRA: ${result.blockRecipe}`,
                        dateColumnIndex: -1,
                        descriptionColumnIndex: -1,
                        amountColumnIndex: -1
                    };
                }

                return {
                    ...prev,
                    extractionMode: 'COLUMNS',
                    dateColumnIndex: result.dateColumnIndex,
                    descriptionColumnIndex: result.descriptionColumnIndex,
                    amountColumnIndex: result.amountColumnIndex,
                    ignoredKeywords: result.ignoredKeywords || []
                };
            });

            showToast("Padrão aprendido!", "success");
        } catch (e: any) {
            console.error("[PatternTeacher] Fail:", e);
            showToast("Erro ao aprender o padrão.", "error");
        } finally {
            setIsInferringMapping(false);
            setLearnedPatternSource(null);
        }
    }, [learnedPatternSource, isInferringMapping, rawBase64, fullFileText, setActiveMapping, showToast]);

    return {
        isInferringMapping,
        learnedPatternSource,
        setLearnedPatternSource,
        handleApplyCorrectionPattern
    };
};

import { GoogleGenAI, Type } from "@google/genai";
import { ReceiptAnalysisResult } from "../types";
import { Logger } from "./monitoringService";

const getAIClient = () => {
    if (!process.env.API_KEY) throw new Error("API Key missing");
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

async function callWithRetry<T>(fn: () => Promise<T>, retries = 1): Promise<T> {
    try {
        return await fn();
    } catch (error: any) {
        if (retries > 0) {
            await new Promise(r => setTimeout(r, 1000));
            return callWithRetry(fn, retries - 1);
        }
        throw error;
    }
}

export const analyzeReceipt = async (file: File): Promise<ReceiptAnalysisResult> => {
  try {
    const base64Data = await new Promise<string>((resolve) => {
      const reader = new FileReader();
      reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
      reader.readAsDataURL(file);
    });

    return await callWithRetry(async () => {
        const ai = getAIClient();

        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview', // Flash para análise rápida de comprovantes
          contents: {
            parts: [
              { inlineData: { mimeType: file.type, data: base64Data } },
              { text: "Extraia valor, data, pagador e recebedor deste comprovante financeiro." }
            ]
          },
          config: {
            temperature: 0,
            maxOutputTokens: 600,
            thinkingConfig: { thinkingBudget: 0 },
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                isValid: { type: Type.BOOLEAN },
                amount: { type: Type.NUMBER },
                date: { type: Type.STRING },
                recipient: { type: Type.STRING },
                sender: { type: Type.STRING },
                reason: { type: Type.STRING }
              },
              required: ["isValid"]
            }
          }
        });

        const text = response.text;
        return text ? JSON.parse(text) : { isValid: false, reason: "Falha na interpretação da IA" };
    });

  } catch (error) {
    Logger.error("Erro ao analisar comprovante via Gemini", error);
    return { isValid: false, reason: "Erro técnico no processamento." } as any;
  }
};

import { supabase } from './supabaseClient';
import { FileModel } from '../types';
import { Logger } from './monitoringService';
import { get, set, del } from 'idb-keyval';

const PERSISTENT_STORAGE_KEY = 'identificapix-models-storage-v12';

export const modelService = {
    /**
     * Recupera os modelos do usuário.
     * V12: Sincronia total com o servidor para eliminar modelos excluídos (ghosts).
     */
    getUserModels: async (userId: string): Promise<FileModel[]> => {
        try {
            // 1. Busca a verdade absoluta no servidor
            const { data, error } = await supabase
                .from('file_models')
                .select('*')
                .eq('is_active', true)
                .eq('user_id', userId);

            if (error) throw error;

            const mapDbRowToModel = (row: any): FileModel => ({
                id: row.id,
                name: row.name,
                user_id: row.user_id,
                version: row.version || 1,
                lineage_id: row.lineage_id || row.id,
                is_active: row.is_active,
                status: row.status || 'draft',
                fingerprint: typeof row.fingerprint === 'string' ? JSON.parse(row.fingerprint) : row.fingerprint,
                mapping: typeof row.mapping === 'string' ? JSON.parse(row.mapping) : row.mapping,
                parsingRules: row.parsing_rules ? (typeof row.parsing_rules === 'string' ? JSON.parse(row.parsing_rules) : row.parsing_rules) : { ignoredKeywords: [], rowFilters: [] },
                snippet: row.snippet,
                createdAt: row.created_at || new Date().toISOString(),
                lastUsedAt: row.last_used_at
            });

            const remoteModels = data ? data.map(mapDbRowToModel) : [];

            // 2. Sobrescreve o cache local com a lista limpa do servidor
            await set(PERSISTENT_STORAGE_KEY, remoteModels);

            console.log(`[ModelService] Sincronizado: ${remoteModels.length} modelos ativos encontrados.`);
            return remoteModels;

        } catch (e) {
            console.warn("[ModelService] Falha na rede, tentando ler cache local...", e);
            const cached = await get(PERSISTENT_STORAGE_KEY);
            return Array.isArray(cached) ? cached : [];
        }
    },

    saveModel: async (model: Omit<FileModel, 'id' | 'createdAt'>): Promise<FileModel | null> => {
        try {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error("Sessão expirada.");

            // Desativa versões anteriores da mesma linhagem
            if (model.lineage_id) {
                await supabase.from('file_models')
                    .update({ is_active: false })
                    .eq('lineage_id', model.lineage_id);
            }

            const { data, error } = await supabase
                .from('file_models')
                .insert([{
                    name: model.name,
                    user_id: session.user.id,
                    version: model.version || 1,
                    lineage_id: model.lineage_id,
                    is_active: true,
                    status: model.status || 'approved',
                    fingerprint: model.fingerprint,
                    mapping: model.mapping,
                    parsing_rules: model.parsingRules,
                    snippet: model.snippet
                }])
                .select('*')
                .single();

            if (error) throw error;

            // Invalida cache local para forçar refresh na próxima leitura
            await del(PERSISTENT_STORAGE_KEY);

            return data;
        } catch (error) {
            Logger.error("Erro ao salvar modelo", error);
            throw error;
        }
    },

    /**
     * Atualiza um contrato de modelo existente sem criar novo registro.
     * Usado para o fluxo de Refinamento/Reaprendizado no Laboratório.
     */
    updateModel: async (id: string, updates: Omit<FileModel, 'id' | 'createdAt' | 'user_id' | 'lineage_id' | 'version' | 'is_active'>): Promise<FileModel | null> => {
        try {
            const { data, error } = await supabase
                .from('file_models')
                .update({
                    name: updates.name,
                    status: updates.status || 'approved',
                    fingerprint: updates.fingerprint,
                    mapping: updates.mapping,
                    parsing_rules: updates.parsingRules,
                    snippet: updates.snippet,
                    last_used_at: new Date().toISOString()
                })
                .eq('id', id)
                .select('*')
                .single();

            if (error) throw error;

            // Invalida cache local
            await del(PERSISTENT_STORAGE_KEY);

            return data;
        } catch (error) {
            Logger.error("Erro ao atualizar modelo existente", error);
            throw error;
        }
    },

    deleteModel: async (id: string) => {
        const { error } = await supabase.from('file_models').delete().eq('id', id);
        if (!error) {
            await del(PERSISTENT_STORAGE_KEY); // Limpa cache
            return true;
        }
        return false;
    },

    getAllModelsAdmin: async (): Promise<FileModel[]> => {
        const { data, error } = await supabase.from('file_models').select('*').order('created_at', { ascending: false });
        if (error) return [];
        return data as any[];
    },

    updateModelName: async (id: string, name: string) => {
        const { error } = await supabase.from('file_models').update({ name }).eq('id', id);
        if (!error) {
            await del(PERSISTENT_STORAGE_KEY);
            return true;
        }
        return false;
    }
};

import React, { useState, useMemo, useContext, useCallback, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { useUI } from '../../contexts/UIContext';
import { AppContext } from '../../contexts/AppContext'; 
import { useAuth } from '../../contexts/AuthContext';
import { modelService } from '../../services/modelService';
import { FileModel, Transaction } from '../../types';
import { SparklesIcon, TableCellsIcon, ShieldCheckIcon } from '../Icons';

// Sub-componentes
import { SpreadsheetRenderer } from './preprocessor/SpreadsheetRenderer';
import { PDFRenderer } from './preprocessor/PDFRenderer';
import { SimulatedResultsTable } from './preprocessor/SimulatedResultsTable';
import { MappingControls } from './preprocessor/MappingControls';
import { TeachingBanner } from './preprocessor/TeachingBanner';
import { PreprocessorHeader } from './preprocessor/PreprocessorHeader';

// Hooks
import { useFileProcessing } from '../../hooks/useFileProcessing';
import { useSimulation } from '../../hooks/useSimulation';
import { useAIPatternTeacher } from '../../hooks/useAIPatternTeacher';
import { FileUploader } from '../FileUploader';

export const FilePreprocessorModal: React.FC<{ 
    onClose: () => void; 
    initialFile?: any;
    initialModel?: FileModel; 
    onSuccess?: (model: FileModel, data: Transaction[]) => void;
    mode?: 'create' | 'test' | 'refine'; 
}> = ({ onClose, initialFile, initialModel, onSuccess, mode = 'create' }) => {
    const { showToast } = useUI();
    const { user } = useAuth(); 
    const context = useContext(AppContext);

    const effectiveIgnoreKeywords = context?.effectiveIgnoreKeywords || [];
    const contributionKeywords = context?.contributionKeywords || [];
    const fetchModels = context?.fetchModels;

    const [uploadedFile, setUploadedFile] = useState<{ content: string, fileName: string, rawFile?: File, base64?: string } | null>(null);

    useEffect(() => {
        if (mode === 'refine' && initialModel && !uploadedFile && !initialFile) {
            setUploadedFile({
                content: initialModel.snippet || "",
                fileName: initialModel.name,
                rawFile: undefined
            });
        }
    }, [mode, initialModel, uploadedFile, initialFile]);

    const activeFile = initialFile || uploadedFile || null;
    const isPdf = useMemo(() => /\.pdf$/i.test(activeFile?.fileName || ''), [activeFile]);

    const cleaningKeywords = useMemo(() => [
        ...(effectiveIgnoreKeywords || []), 
        ...(contributionKeywords || [])
    ], [effectiveIgnoreKeywords, contributionKeywords]);

    const { 
        gridData, setGridData, isGridLoading,
        activeMapping, setActiveMapping, detectedFingerprint, rawBase64
    } = useFileProcessing({ activeFile, initialModel, isPdf });

    const {
        processedTransactions, isSimulating, editingRowIndex, editingRowData, 
        setEditingRowData, startEdit, saveRow, cancelEdit, runSimulation
    } = useSimulation({ 
        gridData, 
        activeMapping, 
        cleaningKeywords, 
        rawBase64: activeFile?.base64 || rawBase64 
    });

    const {
        isInferringMapping, learnedPatternSource, setLearnedPatternSource, handleApplyCorrectionPattern
    } = useAIPatternTeacher({ 
        gridData, 
        setGridData, 
        setActiveMapping, 
        showToast,
        fullFileText: activeFile?.content,
        rawBase64: activeFile?.base64 || rawBase64
    });

    const [isSavingModel, setIsSavingModel] = useState(false);
    const [showNameModal, setShowNameModal] = useState(false);
    const [pendingAction, setPendingAction] = useState<'draft' | 'approved'>('draft');
    const [modelName, setModelName] = useState(initialModel?.name || '');

    const handlePersistModel = useCallback(async (approvalStatus: 'draft' | 'approved', finalName: string) => {
        if (!activeMapping || !detectedFingerprint || !user) return;

        setIsSavingModel(true);
        try {
            const finalSnippet = gridData.map(row => row.join(';')).join('\n');
            const learnedKeywords = activeMapping.ignoredKeywords || [];

            const modelData: any = { 
                name: finalName, 
                user_id: user.id, 
                version: initialModel ? initialModel.version : 1, 
                lineage_id: initialModel ? initialModel.lineage_id : `mod-${Date.now()}`, 
                is_active: true, 
                fingerprint: { ...detectedFingerprint }, 
                mapping: { ...activeMapping }, 
                parsingRules: { ignoredKeywords: learnedKeywords, rowFilters: [] }, 
                snippet: finalSnippet, 
                status: approvalStatus 
            };

            let saved;
            if (initialModel?.id) {
                // REFINAMENTO: Atualiza o registro existente
                saved = await modelService.updateModel(initialModel.id, modelData);
                if (saved) showToast("Contrato de modelo atualizado!", "success");
            } else {
                // CRIAÇÃO: Insere um novo registro
                saved = await modelService.saveModel(modelData);
                if (saved) showToast("Novo modelo salvo com sucesso!", "success");
            }

            if (saved) {
                if (fetchModels) await fetchModels();
                if (onSuccess) onSuccess(saved as FileModel, []);
                onClose();
            }
        } catch (e: any) { 
            showToast("Erro ao salvar padrão.", "error"); 
        } finally { setIsSavingModel(false); }
    }, [activeMapping, detectedFingerprint, user, gridData, initialModel, onSuccess, onClose, showToast, fetchModels]);

    return createPortal(
        <div className="fixed inset-0 z-[9999] bg-[#050B14]/90 backdrop-blur-md flex items-center justify-center p-2 sm:p-4 animate-fade-in overflow-hidden">
            <div className="bg-white dark:bg-[#0F172A] w-full max-w-[1600px] h-full max-h-[95dvh] rounded-[2.5rem] shadow-2xl border border-white/10 flex flex-col overflow-hidden animate-scale-in relative">

                <PreprocessorHeader 
                    fileName={activeFile?.fileName || 'Laboratório de IA'} 
                    canApprove={processedTransactions.length > 0} 
                    onApprove={() => { setPendingAction('approved'); setShowNameModal(true); }}
                    onClose={onClose}
                />

                <div className="px-6 py-3 bg-slate-50 dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 flex items-center justify-between shrink-0">
                    <MappingControls mapping={activeMapping} setMapping={setActiveMapping} columnCount={gridData[0]?.length || 0} onSimulate={runSimulation} gridData={gridData} />
                </div>

                <div className="flex-1 flex flex-col lg:flex-row overflow-hidden min-h-0">
                    <section className="flex-1 flex flex-col border-r border-slate-200 dark:border-slate-800 bg-slate-100 dark:bg-[#0B1120] relative">
                        {isGridLoading ? (
                            <div className="absolute inset-0 flex flex-col items-center justify-center"><div className="animate-spin rounded-full h-8 w-8 border-4 border-indigo-500 border-t-transparent mb-3"></div><p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Lendo arquivo...</p></div>
                        ) : !activeFile ? (
