import { useState, useCallback } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { FileModel, Transaction } from '../types';

interface UseAIPatternTeacherProps {
    gridData: string[][];
    setGridData: (data: string[][]) => void;
    setActiveMapping: (mapping: any) => void;
    showToast: (msg: string, type: 'success' | 'error') => void;
    fullFileText?: string;
    rawBase64?: string; 
}

export const useAIPatternTeacher = ({
    gridData,
    setGridData,
    setActiveMapping,
    showToast,
    fullFileText,
    rawBase64
}: UseAIPatternTeacherProps) => {
    const [isInferringMapping, setIsInferringMapping] = useState(false);
    const [learnedPatternSource, setLearnedPatternSource] = useState<{ originalRaw: string[], corrected: any } | null>(null);

    const handleApplyCorrectionPattern = useCallback(async (extractionMode: 'COLUMNS' | 'BLOCK' = 'COLUMNS') => {
        if (!learnedPatternSource || isInferringMapping) return;

        setIsInferringMapping(true);
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

        try {
            const isBlockMode = extractionMode === 'BLOCK';

            const instruction = isBlockMode 
            ? `VOCÊ É UM ENGENHEIRO DE REPRODUÇÃO ESTRUTURAL. O Admin editou uma linha modelo para te ensinar como extrair dados.
            --- LINHA MODELO ---
            Bruto: "${learnedPatternSource.originalRaw.join(' | ')}"
            Esperado: Date:"${learnedPatternSource.corrected.date}" | Desc:"${learnedPatternSource.corrected.description}" | Amount:"${learnedPatternSource.corrected.amount}"
            Gere a "blockRecipe" JSON com a regra algorítmica e "confidence".`

            : `VOCÊ É UM EXTRATOR DE ÍNDICES DE COLUNA. Determine os índices de 0 a N correspondentes:
            BRUTO: "${learnedPatternSource.originalRaw.join(' ; ')}"
            GABARITO: Data: "${learnedPatternSource.corrected.date}", Nome: "${learnedPatternSource.corrected.description}", Valor: "${learnedPatternSource.corrected.amount}"`;

            const contents: any = { parts: [] };

            if (isBlockMode && rawBase64) {
                contents.parts.push({
                    inlineData: {
                        data: rawBase64,
                        mimeType: 'application/pdf'
                    }
                });
            } else if (fullFileText) {
                // FATIAMENTO: Envia apenas os primeiros 5000 caracteres como contexto para economizar tokens
                contents.parts.push({ text: `CONTEÚDO DO DOCUMENTO (AMOSTRA):\n${fullFileText.substring(0, 5000)}` });
            }

            contents.parts.push({ text: instruction });

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview', 
                contents: contents,
                config: { 
                    temperature: 0,
                    maxOutputTokens: 800,
                    thinkingConfig: { thinkingBudget: 0 },
                    responseMimeType: "application/json",
                    responseSchema: isBlockMode ? {
                        type: Type.OBJECT,
                        properties: {
                            blockRecipe: { type: Type.STRING },
                            confidence: { type: Type.NUMBER }
                        },
                        required: ["blockRecipe"]
                    } : {
                        type: Type.OBJECT,
                        properties: {
                            dateColumnIndex: { type: Type.INTEGER },
                            descriptionColumnIndex: { type: Type.INTEGER },
                            amountColumnIndex: { type: Type.INTEGER },
                            ignoredKeywords: { type: Type.ARRAY, items: { type: Type.STRING } }
                        },
                        required: ["dateColumnIndex", "descriptionColumnIndex", "amountColumnIndex", "ignoredKeywords"]
                    }
                }
            });

            const result = JSON.parse(response.text || "{}");

            // Ordem crítica: primeiro define o novo mapeamento (gatilho de simulação)
            setActiveMapping((prev: any) => {
                if (isBlockMode) {
                    return {
                        ...prev,
                        extractionMode: 'BLOCK',
                        blockContract: `CONTRATO RÍGIDO: [${learnedPatternSource.originalRaw.join(' | ')}] -> Date:${learnedPatternSource.corrected.date} | Desc:${learnedPatternSource.corrected.description} | Amount:${learnedPatternSource.corrected.amount}. REGRA: ${result.blockRecipe}`,
                        dateColumnIndex: -1,
                        descriptionColumnIndex: -1,
                        amountColumnIndex: -1
                    };
                }

                return {
                    ...prev,
                    extractionMode: 'COLUMNS',
                    dateColumnIndex: result.dateColumnIndex,
                    descriptionColumnIndex: result.descriptionColumnIndex,
                    amountColumnIndex: result.amountColumnIndex,
                    ignoredKeywords: result.ignoredKeywords || []
                };
            });

            // Feedback e limpeza de fonte de ensino
            showToast("Padrão aprendido!", "success");
            setLearnedPatternSource(null);
        } catch (e: any) {
            console.error("[PatternTeacher] Fail:", e);
            showToast("Erro ao aprender o padrão.", "error");
        } finally {
            setIsInferringMapping(false);
        }
    }, [learnedPatternSource, isInferringMapping, rawBase64, fullFileText, setActiveMapping, showToast]);

    return {
        isInferringMapping,
        learnedPatternSource,
        setLearnedPatternSource,
        handleApplyCorrectionPattern
    };
};

import { useState, useCallback, useEffect, useRef } from 'react';
import { Transaction } from '../types';
import { DateResolver } from '../core/processors/DateResolver';
import { AmountResolver } from '../core/processors/AmountResolver';
import { TypeResolver } from '../core/processors/TypeResolver';
import { NameResolver } from '../core/processors/NameResolver';
import { extractTransactionsWithModel, getRawStructuralDump } from '../services/geminiService';

interface SafeTransaction extends Transaction {
    sourceIndex?: number;
    isValid?: boolean;
    status?: 'valid' | 'error' | 'edited' | 'ignored' | 'pending';
    sourceRawSnippet?: string[];
}

interface UseSimulationProps {
    gridData: string[][];
    activeMapping: any;
    cleaningKeywords: string[];
    rawBase64?: string;
}

export const useSimulation = ({ gridData, activeMapping, cleaningKeywords, rawBase64 }: UseSimulationProps) => {
    const [processedTransactions, setProcessedTransactions] = useState<SafeTransaction[]>([]);
    const [editingRowIndex, setEditingRowIndex] = useState<number | null>(null);
    const [editingRowData, setEditingRowData] = useState<SafeTransaction | null>(null);
    const [isSimulating, setIsSimulating] = useState(false);

    const lastDataRef = useRef<string>('');
    const lastMappingRef = useRef<string>('');
    const lastContractRef = useRef<string | undefined>(undefined);
    const initialReadDone = useRef<string | null>(null);
    const isRunningRef = useRef(false);

    const runSimulation = useCallback(async () => {
        if (!gridData || gridData.length === 0 || isRunningRef.current) {
            if (!gridData || gridData.length === 0) setProcessedTransactions([]);
            return;
        }

        const mapping = activeMapping || { extractionMode: 'COLUMNS' };
        const isBlockMode = mapping.extractionMode === 'BLOCK';
        isRunningRef.current = true;

        // 🧱 MODO BLOCO (EXECUÇÃO IA)
        if (isBlockMode) {
            const isVisualDoc = gridData[0]?.[0] === '[DOCUMENTO_VISUAL]' || gridData[0]?.[0] === '[DOCUMENTO_PDF_VISUAL]';

            // FASE 1: Dump Bruto (Aguardando Ensino)
            if (isVisualDoc && !mapping.blockContract) {
                if (rawBase64 && initialReadDone.current !== rawBase64.substring(0, 100)) {
                    setIsSimulating(true);
                    try {
                        const rawLines = await getRawStructuralDump(rawBase64);
                        const mapped = rawLines.map((line: string, i: number) => ({
                            id: `raw-dump-${i}-${Date.now()}`,
                            date: "---",
                            description: line, 
                            rawDescription: line,
                            amount: 0,
                            originalAmount: "0.00",
                            isValid: false,
                            status: 'pending' as const,
                            sourceIndex: i,
                            sourceRawSnippet: [line]
                        }));
                        setProcessedTransactions(mapped);
                        initialReadDone.current = rawBase64.substring(0, 100);
                        lastContractRef.current = undefined;
                    } catch (e) {
                        console.error("[Simulation] Falha no dump bruto:", e);
                    } finally {
                        setIsSimulating(false);
                        isRunningRef.current = false;
                    }
                } else {
                    isRunningRef.current = false;
                }
                return;
            }

            // FASE 2: Execução Real do Padrão Aprendido
            if (isVisualDoc && mapping.blockContract) {
                const contractChanged = mapping.blockContract !== lastContractRef.current;

                if (rawBase64 && (initialReadDone.current !== rawBase64.substring(0, 100) || contractChanged)) {
                    setIsSimulating(true);
                    try {
                        console.log("[Simulation] EXECUTANDO PADRÃO APRENDIDO...");
                        const aiResults = await extractTransactionsWithModel("", mapping.blockContract, rawBase64);

                        if (aiResults && Array.isArray(aiResults) && aiResults.length > 0) {
                            const mapped = aiResults.map((tx: any, i: number) => ({
                                id: `ai-extracted-${i}-${Date.now()}`,
                                date: tx.date || "---",
                                description: tx.description || "---",
                                rawDescription: tx.description || "",
                                amount: tx.amount || 0,
                                originalAmount: String(tx.amount || "0"),
                                isValid: true,
                                status: 'valid' as const,
                                sourceIndex: 0
                            }));
                            setProcessedTransactions(mapped);
                            initialReadDone.current = rawBase64.substring(0, 100);
                            lastContractRef.current = mapping.blockContract;
                        }
                    } catch (e) {
                        console.error("[Simulation] Falha na extração ensinada:", e);
                    } finally {
                        setIsSimulating(false);
                        isRunningRef.current = false;
                    }
                } else {
                    isRunningRef.current = false;
                }
                return;
            }
        }

        // 🚀 MODO COLUNAS (DETERMINÍSTICO)
        const isManualMappingComplete = mapping.dateColumnIndex >= 0 && mapping.amountColumnIndex >= 0;

        if (!isManualMappingComplete) {
            if (!isBlockMode) {
                const initialPreview = gridData.slice(0, 100).map((row, i) => ({
                    id: `raw-${i}-${Date.now()}`,
                    date: "---",
                    description: row.join(' ').substring(0, 150),
                    rawDescription: row.join(';'),
                    amount: 0,
                    originalAmount: "0.00",
                    isValid: false,
                    status: 'pending' as const,
                    sourceIndex: i,
                    sourceRawSnippet: row
                }));
                setProcessedTransactions(initialPreview);
            }
            isRunningRef.current = false;
            return;
        }

        setIsSimulating(true);
        try {
            const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, paymentMethodColumnIndex, skipRowsStart, ignoredKeywords } = mapping;
            const newTransactions: SafeTransaction[] = [];
            const yearAnchor = DateResolver.discoverAnchorYear(gridData);

            gridData.forEach((cols, index) => {
                const isSkipped = index < (skipRowsStart || 0);
                const rawDate = dateColumnIndex >= 0 ? (cols[dateColumnIndex] || '') : '';
                const rawDesc = descriptionColumnIndex >= 0 ? (cols[descriptionColumnIndex] || '') : '';
                const rawAmount = amountColumnIndex >= 0 ? (cols[amountColumnIndex] || '') : '';

                if (!rawDate && !rawDesc && !rawAmount) return;

                const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
                const amountStr = AmountResolver.clean(rawAmount);
                const amountValue = parseFloat(amountStr);
                const cleanedName = NameResolver.clean(rawDesc, ignoredKeywords || [], cleaningKeywords);

                newTransactions.push({ 
                    id: `sim-${index}-${Date.now()}`,
                    date: isoDate || rawDate || "---", 
                    description: cleanedName, 
                    rawDescription: rawDesc || "---", 
                    paymentMethod: (paymentMethodColumnIndex !== undefined && paymentMethodColumnIndex >= 0 && cols[paymentMethodColumnIndex]) ? cols[paymentMethodColumnIndex] : TypeResolver.resolveFromDescription(rawDesc),
                    amount: isNaN(amountValue) ? 0 : amountValue, 
                    originalAmount: rawAmount, 
                    cleanedDescription: cleanedName, 
                    contributionType: 'AUTO', 
                    sourceIndex: index, 
                    sourceRawSnippet: cols,
                    isValid: !!isoDate && !isNaN(amountValue), 
                    status: isSkipped ? 'ignored' : 'valid'
                });
            });
            setProcessedTransactions(newTransactions);
        } finally {
            setIsSimulating(false);
            isRunningRef.current = false;
        }
    }, [gridData, activeMapping, cleaningKeywords, rawBase64]);

    useEffect(() => {
        const dataHash = gridData.length > 0 ? `${gridData.length}-${gridData[0].join('|').substring(0, 50)}` : 'empty';
        const mappingKey = JSON.stringify(activeMapping);
        if (dataHash !== lastDataRef.current || mappingKey !== lastMappingRef.current) {
            lastDataRef.current = dataHash;
            lastMappingRef.current = mappingKey;
            runSimulation();
        }
    }, [gridData, activeMapping, runSimulation]);

    return {
        processedTransactions, isSimulating, runSimulation, editingRowIndex, editingRowData, setEditingRowData,
        startEdit: (tx: any, idx: number) => { setEditingRowIndex(idx); setEditingRowData({ ...tx }); },
        saveRow: (onLearned?: (raw: string[], corrected: any) => void) => {
            if (editingRowIndex !== null && editingRowData) {
                const updatedTx = { ...editingRowData, status: 'edited' as const, isValid: true };
                if (onLearned) onLearned(updatedTx.sourceRawSnippet || [], updatedTx);
                setProcessedTransactions(prev => { const n = [...prev]; n[editingRowIndex] = updatedTx; return n; });
                setEditingRowIndex(null);
            }
        },
        cancelEdit: () => setEditingRowIndex(null)
    };
};

